  clearForms() {
    this.isInserting = false;
    this.isEditing = false;
    this.isUpdate = false;
    this.isAdd = false;
    this.BranchForm.reset();
    this.GeoForm.reset();
  }
  Edit(node: Tree<Node>): void {
    this.hasSupervisor = false;
    this.currentTreeNode = node;
    if (!node.data.parent_id && node.children) {
      //مركز رئيسي
      this.GetBranchByID(node.data.node_code, true);
      this.isInserting = false;
      this.isEditing = true;
      this.isAdd = false;
      this.isUpdate = false;
    }
    if (node.data.parent_id && node.children) {
      //فرع
      console.log(node);
      this.GetBranchByID(node.data.parent_id, true);
      this.isInserting = false;
      this.isEditing = true;
      this.isAdd = false;
      this.isUpdate = false;
    }
    if (node.data.parent_id && !node.children) {
      //جغرافي
      this.GetGeoByID(node.data.node_code, node.data.parent_id, true);
      this.isInserting = false;
      this.isEditing = false;
      this.isAdd = false;
      this.isUpdate = true;
    }
  }
  Add(node: Tree<Node>): void {
    if (node.data.parent_id != null && node.children) {
      //فرع
      this.GetGeoAdd(node.data.node_code, true);
      this.isInserting = false;
      this.isEditing = false;
      this.isAdd = true;
      this.isUpdate = false;
    }
  }
  async Delete(node: Tree<Node>): Promise<void> {
    if (
      !node.children &&
      (await this.alertServices.SaveAlert("هل تريد الحذف؟"))
    ) {
      this.showLoader = true;
      this.http
        .post(this.env.API_URL + "api/Branch/GetGeoDelete", {
          geo_area_code: node.data.node_code.toString(),
          branch_code: node.data.parent_id,
        })
        .subscribe({
          next: (data) => {
            this.showLoader = false;
            this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
          },
          error: (err) => {
            console.log(err);
            this.alertServices.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }
  async GetBranchByID(branch_code, isEditing) {
    this.http
      .get<BranchReference>(
        `${this.env.API_URL}api/Branch/GetbranchById?branch_code=${branch_code}`
      )
      .subscribe({
        next: async (data) => {
          console.log(data);
          this.BranchInfo = data[0];
          if (isEditing) this.patchDataValue();
          this.isEditing = isEditing;
          this.GovName = await this.ReferencesService.getGovernorate();
          if (this.BranchInfo.gov_code) {
            this.DistName = await this.ReferencesService.getDistrict(
              this.BranchInfo.gov_code
            );
            if (this.BranchInfo.dist_code)
              this.VillName = await this.ReferencesService.getVillage(
                this.BranchInfo.gov_code,
                this.BranchInfo.dist_code
              );
          }
          this.IndivLoanTypes = await this.ReferencesService.GetIndivLoan();
          this.GroupLoanTypes = await this.ReferencesService.GetGroupLoan();
          this.EndPeriodOption =
            await this.ReferencesService.GetEndPeriodOption();
          this.EndPeriodoptionWithoutDel =
            await this.ReferencesService.GetEndPeriodoptionWithoutDel();
          this.GlSystem = await this.ReferencesService.GetGlSystem();
          this.GetGlGen = await this.ReferencesService.GetGlGen();
          this.IscoreBank = await this.ReferencesService.getIscoreBank(
            parseInt(this.BranchInfo.branch_code)
          );
          this.showLoader = false;
        },

        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }
