  async EditGeo() {
    if (this.GeoForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد تعديل البيانات؟")) {
        this.showLoader = true;
        let node: Tree<Node> = this.currentTreeNode;
        this.http
          .post(this.env.API_URL + "api/Branch/GetGeoUpdate", {
            geo_area_code: node.data.node_code.toString(),
            geo_area_name: this.GeoForm.value.tree_name.toString(),
            branch_code: node.data.parent_id,
            poly: this.GeoInfo[0].poly,
          })
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }
  async InsertGeo() {
    if (this.GeoForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد الاضافة؟")) {
        this.showLoader = true;
        if (this.GeoForm.value.poly != "") {
          this.http
            .post(this.env.API_URL + "api/Branch/GetGeoAdd", {
              branch_code: this.GeoForm.value.tree_code.toString(),
              geo_area_name: this.GeoForm.value.tree_name.toString(),
              poly: this.GeoForm.value.poly,
            })
            .subscribe({
              next: (data) => {
                this.showLoader = false;
                this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
              },
              error: (err) => {
                console.log(err);
                this.alertServices.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        } else {
          this.http
            .post(this.env.API_URL + "api/Branch/GetGeoAdd", {
              branch_code: this.GeoForm.value.tree_code.toString(),
              geo_area_name: this.GeoForm.value.tree_name.toString(),
            })
            .subscribe({
              next: (data) => {
                this.showLoader = false;
                this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
              },
              error: (err) => {
                console.log(err);
                this.alertServices.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        }
      }
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }
